    /**
     * 获取 B站视频信息 - 改进版，优先使用官方API
     * 基于 GitHub 研究：bilibili-api Kotlin 库实现
     *
     * 策略：
     * 1. 优先使用 B站官方 API
     * 2. 官方API失败后，尝试第三方API作为备用
     */
    private suspend fun fetchBilibiliInfo(url: String): Result<VideoDownloadInfo> {
        Log.d(TAG, "Fetching Bilibili info for: $url")

        // 策略1: 尝试官方API
        val officialResult = fetchBilibiliOfficialAPI(url)
        if (officialResult.isSuccess) {
            Log.d(TAG, "Official API success")
            return officialResult
        }
        Log.w(TAG, "Official API failed: ${officialResult.exceptionOrNull()?.message}")

        // 策略2: 尝试第三方API（备用）
        return fetchBilibiliThirdPartyAPI(url)
    }

    /**
     * 使用 B站官方 API 解析
     * 参考 bilibili-api (Kotlin): https://github.com/czp3009/bilibili-api
     *
     * API 端点：
     * - 视频信息: https://api.bilibili.com/x/web-interface/view?bvid={bvid}
     * - 播放地址: https://api.bilibili.com/x/player/playurl?bvid={bvid}&cid={cid}
     */
    private suspend fun fetchBilibiliOfficialAPI(url: String): Result<VideoDownloadInfo> = withContext(Dispatchers.IO) {
        try {
            // 1. 如果是 b23.tv 短链接，先解析真实 URL
            var realUrl = url
            if (url.contains("b23.tv")) {
                val resolved = resolveB23ShortLink(url)
                if (resolved != null) {
                    realUrl = resolved
                    Log.d(TAG, "Resolved b23.tv -> $realUrl")
                } else {
                    return@withContext Result.failure(Exception("无法解析b23.tv短链接"))
                }
            }

            // 2. 提取视频标识（BV号或av号）
            val videoId = extractBVID(realUrl)
            if (videoId == null) {
                return@withContext Result.failure(Exception("无法提取BV号或av号"))
            }
            Log.d(TAG, "Video ID: $videoId")

            // 获取Cookie（如果有配置）
            val cookie = getCookieForPlatform(url)
            if (cookie != null) {
                Log.d(TAG, "Using configured cookies for Bilibili API")
            }

            // 3. 获取视频信息（获取 cid）- 支持 BV 号和 av 号
            val infoUrl = if (videoId.startsWith("av")) {
                "https://api.bilibili.com/x/web-interface/view?aid=${videoId.removePrefix("av")}"
            } else {
                "https://api.bilibili.com/x/web-interface/view?bvid=$videoId"
            }
            val infoRequestBuilder = Request.Builder()
                .url(infoUrl)
                .header("User-Agent", getUserAgent())
                .header("Referer", "https://www.bilibili.com/")

            // 添加Cookie
            if (cookie != null) {
                infoRequestBuilder.header("Cookie", cookie)
            }

            val infoRequest = infoRequestBuilder.build()

            val infoResponse = client.newCall(infoRequest).execute()
            val infoBody = infoResponse.body?.string() ?: return@withContext Result.failure(IOException("空响应"))
            val infoJson = JSONObject(infoBody)

            if (infoJson.optInt("code", -1) != 0) {
                val errorMsg = infoJson.optString("message")
                // 检查是否是需要Cookie的错误
                if (errorMsg.contains("登录") || errorMsg.contains("会员") || errorMsg.contains("权限")) {
                    return@withContext Result.failure(
                        Exception("❌ 需要登录或会员权限\n\n错误信息: $errorMsg\n\n解决方案：\n• 在设置中配置B站Cookie（SESSDATA）\n• 或使用「导入本地视频」功能")
                    )
                }
                return@withContext Result.failure(Exception("API错误: $errorMsg"))
            }

            val data = infoJson.getJSONObject("data")
            val cid = data.optLong("cid")
            val title = data.optString("title")
            val cover = data.optString("pic").replace("\\/\\\\/", "/")
            val duration = data.optInt("duration")
            val author = data.optJSONObject("owner")?.optString("name") ?: "未知UP主"

            Log.d(TAG, "Video info: $title, cid=$cid")

            // 4. 获取播放URL - 使用DASH格式（fnval=4048支持全部格式）
            val bvParam = if (videoId.startsWith("av")) "avid=${videoId.removePrefix("av")}" else "bvid=$videoId"
            val playUrl = "https://api.bilibili.com/x/player/playurl?$bvParam&cid=$cid&qn=116&fnval=4048&fnver=0&fourk=1"
            val playRequestBuilder = Request.Builder()
                .url(playUrl)
                .header("User-Agent", getUserAgent())
                .header("Referer", "https://www.bilibili.com/")

            if (cookie != null) {
                playRequestBuilder.header("Cookie", cookie)
            }

            val playRequest = playRequestBuilder.build()
            val playResponse = client.newCall(playRequest).execute()
            val playBody = playResponse.body?.string() ?: return@withContext Result.failure(IOException("空响应"))
            val playJson = JSONObject(playBody)

            if (playJson.optInt("code", -1) != 0) {
                val errorMsg = playJson.optString("message")
                if (errorMsg.contains("登录") || errorMsg.contains("会员") || errorMsg.contains("权限")) {
                    return@withContext Result.failure(
                        Exception("❌ 需要登录或会员权限\n\n错误信息: $errorMsg\n\n解决方案：\n• 在设置中配置B站Cookie（SESSDATA）\n• 或使用「导入本地视频」功能")
                    )
                }
                return@withContext Result.failure(Exception("获取播放URL失败: $errorMsg"))
            }

            val playData = playJson.getJSONObject("data")
            val dash = playData.optJSONObject("dash")
            val durl = playData.optJSONArray("durl")

            var videoUrl: String? = null
            var audioUrl: String? = null

            if (durl != null && durl.length() > 0) {
                // MP4格式（包含音视频）
                videoUrl = durl.getJSONObject(0).optString("url")
            } else if (dash != null) {
                // DASH格式 - 选择最佳画质的视频流
                val dashVideo = dash.optJSONArray("video")
                val dashAudio = dash.optJSONArray("audio")

                if (dashVideo != null && dashVideo.length() > 0) {
                    // 按bandwidth降序选择最佳画质（优先选择高码率）
                    var bestBandwidth = 0L
                    for (i in 0 until dashVideo.length()) {
                        val v = dashVideo.getJSONObject(i)
                        val bw = v.optLong("bandwidth", 0)
                        if (bw > bestBandwidth) {
                            bestBandwidth = bw
                            videoUrl = v.optString("baseUrl").takeIf { it.isNotEmpty() }
                                ?: v.optString("base_url")
                        }
                    }
                    // 选择最佳音频质量
                    if (dashAudio != null && dashAudio.length() > 0) {
                        var bestAudioBw = 0L
                        for (i in 0 until dashAudio.length()) {
                            val a = dashAudio.getJSONObject(i)
                            val bw = a.optLong("bandwidth", 0)
                            if (bw > bestAudioBw) {
                                bestAudioBw = bw
                                audioUrl = a.optString("baseUrl").takeIf { it.isNotEmpty() }
                                    ?: a.optString("base_url")
                            }
                        }
                    }
                    Log.d(TAG, "DASH format: best video bandwidth=$bestBandwidth, hasAudio=${audioUrl != null}")
                }
            }

            if (videoUrl != null) {
                Log.d(TAG, "Got video URL from official API, cookies used: ${cookie != null}, hasAudio: ${audioUrl != null}")
                return@withContext Result.success(VideoDownloadInfo(
                    title = title,
                    downloadUrl = videoUrl,
                    cover = cover,
                    duration = duration.toLong(),
                    author = author,
                    cookies = cookie,
                    platform = VideoPlatform.BILIBILI,
                    audioUrl = audioUrl
                ))
            }

            Result.failure(Exception("无法获取播放地址"))

        } catch (e: Exception) {
            Log.e(TAG, "Official API error", e)
            Result.failure(e)
        }
    }

