            Regex("iesdouyin\\.com/share/video/(\\d+)"),
            Regex("v\\.douyin\\.com/([a-zA-Z0-9]+)")
        )

        for (pattern in patterns) {
            val match = pattern.find(url)
            if (match != null) {
                return match.groupValues[1]
            }
        }
        return null
    }

