    data class VideoDownloadInfo(
        val title: String,
        val downloadUrl: String,
        val cover: String? = null,
        val duration: Long = 0,
        val author: String? = null,
        val cookies: String? = null, // 下载时需要的Cookie
        val platform: VideoPlatform = VideoPlatform.UNKNOWN,
        val audioUrl: String? = null // DASH格式的音频流URL
    )

    /**
     * 支持的平台
