    /**
     * 使用指定 API 获取抖音视频信息
     * 支持 Evil0ctal/Douyin_TikTok_Download_API 的返回格式
     */
    private suspend fun fetchDouyinInfoWithApi(api: DouyinApiConfig): Result<VideoDownloadInfo> = withContext(Dispatchers.IO) {
        try {
            val request = Request.Builder()
                .url(api.endpoint)
                .header("User-Agent", getUserAgent())
                .header("Referer", "https://www.douyin.com/")
                .build()

            val response = client.newCall(request).execute()
            val responseBody = response.body?.string() ?: return@withContext Result.failure(IOException("空响应"))

            Log.d(TAG, "[${api.name}] Response: ${responseBody.take(500)}")

            // 检查是否是HTML
            if (responseBody.trim().startsWith("<!DOCTYPE") || responseBody.trim().startsWith("<html")) {
                return@withContext Result.failure(Exception("API返回HTML，可能已失效"))
            }

            val json = JSONObject(responseBody)

            // 格式0: Evil0ctal 混合解析 API 格式
            // {code: 200, msg: "success", data: {platform: "douyin", api_type: "web", video_data: {desc: "...", nwm_video_url: "..."}}}
            if (api.name == "douyin_wtf" && json.has("data")) {
                val data = json.getJSONObject("data")
                val videoData = data.optJSONObject("video_data")

                if (videoData != null) {
                    // 优先使用无水印视频 URL
                    val videoUrl = videoData.optString("nwm_video_url")
                        ?: videoData.optString("wm_video_url")
                        ?: videoData.optString("play_addr")
                        ?: videoData.optString("download_addr")

                    if (videoUrl.isNotEmpty() && videoUrl.startsWith("http")) {
                        val title = videoData.optString("desc")
                            ?: videoData.optString("title")
                            ?: "抖音视频"

                        val author = videoData.optJSONObject("author")?.optString("nickname")
                            ?: videoData.optString("author")
                            ?: videoData.optString("nickname")

                        val cover = videoData.optString("cover")
                            ?: videoData.optString("origin_cover")
                            ?: videoData.optString("dynamic_cover")

                        Log.d(TAG, "[${api.name}] Successfully parsed Evil0ctal format")
                        return@withContext Result.success(VideoDownloadInfo(
                            title = title,
                            downloadUrl = videoUrl,
                            cover = cover,
                            duration = videoData.optLong("duration", 0L),
                            author = author
                        ))
                    }
                }
            }

            // 检查响应状态码
            val code = json.optInt("code")
            if (code != 200 && code != 1 && code != 0) {
                val msg = json.optString("msg") ?: json.optString("message") ?: "未知错误"
                return@withContext Result.failure(Exception("API返回错误($code): $msg"))
            }

            // 解析视频数据 - 支持多种格式
            // 格式1: {code: 200, data: {video: [{play_addr: "..."}], desc: "..."}}
            if (json.has("data")) {
                val data = json.getJSONObject("data")

                // 尝试获取视频 URL
                val videoData = data.optJSONArray("video")?.optJSONObject(0)
                    ?: data.optJSONArray("data")?.optJSONObject(0)
                    ?: data.optJSONObject("video_data")  // 支持 Evil0ctal 格式
                    ?: data

                val videoUrl = videoData.optString("play_addr")
                    ?: videoData.optString("play_addr_https")
                    ?: videoData.optString("nwm_video_url")  // 无水印视频
                    ?: videoData.optString("wm_video_url")   // 有水印视频
                    ?: videoData.optString("url")
                    ?: videoData.optString("video_url")
                    ?: videoData.optString("download_addr")

                val title = data.optString("desc")
                    ?: data.optString("title")
                    ?: videoData.optString("desc")
                    ?: videoData.optString("title")
                    ?: data.optString("text")
                    ?: "抖音视频"

                if (videoUrl.isNotEmpty() && (videoUrl.startsWith("http") || videoUrl.startsWith("//"))) {
                    // 处理相对协议 URL
                    val finalUrl = if (videoUrl.startsWith("//")) "https:$videoUrl" else videoUrl

                    // 提取作者信息
                    val author = data.optJSONObject("author")?.optString("nickname")
                        ?: videoData.optJSONObject("author")?.optString("nickname")
                        ?: data.optString("author")
                        ?: data.optString("nickname")
                        ?: videoData.optString("author")
                        ?: videoData.optString("nickname")

                    val cover = data.optString("cover")
                        ?: data.optString("thumb")
                        ?: data.optString("origin_cover")
                        ?: data.optString("dynamic_cover")
                        ?: videoData.optString("cover")
                        ?: videoData.optString("origin_cover")
                        ?: videoData.optString("dynamic_cover")

                    return@withContext Result.success(VideoDownloadInfo(
                        title = title,
                        downloadUrl = finalUrl,
                        cover = cover,
                        duration = videoData.optLong("duration", 0L),
                        author = author
                    ))
                }
            }

                return@withContext Result.success(VideoDownloadInfo(
                    title = title,
                    downloadUrl = finalUrl,
                    cover = json.optString("cover") ?: json.optString("thumb") ?: json.optString("origin_cover"),
                    duration = json.optLong("duration", 0L),
                    author = json.optString("author") ?: json.optString("nickname")
                ))
            }

            // 格式3: 嵌套在 data.video 或 data.video.play_addr 中
            val nestedVideo = json.optJSONObject("data")?.optJSONObject("video")
            if (nestedVideo != null) {
                val videoUrl = nestedVideo.optString("play_addr")
                    ?: nestedVideo.optString("play_addr_https")
                    ?: nestedVideo.optString("download_addr")
                    ?: nestedVideo.optString("download_addr_https")

                if (videoUrl.isNotEmpty() && (videoUrl.startsWith("http") || videoUrl.startsWith("//"))) {
                    val finalUrl = if (videoUrl.startsWith("//")) "https:$videoUrl" else videoUrl
                    return@withContext Result.success(VideoDownloadInfo(
                        title = json.optJSONObject("data")?.optString("desc") ?: "抖音视频",
                        downloadUrl = finalUrl,
                        cover = nestedVideo.optString("cover") ?: nestedVideo.optString("origin_cover"),
                        duration = nestedVideo.optJSONObject("video")?.optLong("duration", 0L) ?: 0L,
                        author = json.optJSONObject("data")?.optJSONObject("author")?.optString("nickname")
                    ))
                }
            }

            // 无法获取视频链接
            return@withContext Result.failure(Exception("无法从API响应中提取视频链接"))

        } catch (e: Exception) {
            Log.e(TAG, "[${api.name}] Request failed", e)
            Result.failure(e)
        }
    }

    /**
     * 获取 TikTok 视频信息 - 改进版
     * TikTok 和抖音解析逻辑相似，尝试多个 API
     */
    private suspend fun fetchTiktokInfo(url: String): Result<VideoDownloadInfo> {
        Log.d(TAG, "Fetching TikTok info for: $url")

        // TikTok 可以使用与抖音类似的 API
        val apis = listOf(
            // API 1: tikwm (专门用于 TikTok)
            TiktokApiConfig("https://www.tikwm.com/api/?url=$url", "tikwm"),
            // API 2: 通用 API
            TiktokApiConfig("https://api.pearktrue.com/api/v1/parse/tiktok?url=$url", "pearktrue"),
            // API 3: other API
            TiktokApiConfig("https://api.xboba.com/tiktok/video/download?url=$url", "xboba")
        )

        for ((index, api) in apis.withIndex()) {
            try {
                Log.d(TAG, "[${index + 1}/${apis.size}] Trying TikTok API: ${api.name}")

                val result = fetchTiktokInfoWithApi(api)
                if (result.isSuccess) {
                    Log.d(TAG, "Successfully fetched info using: ${api.name}")
                    return result
                }

                Log.w(TAG, "API ${api.name} failed: ${result.exceptionOrNull()?.message}")

                if (index < apis.size - 1) {
                    delay(RETRY_DELAY_MS)
                }
            } catch (e: Exception) {
                Log.e(TAG, "API ${api.name} threw exception", e)
                if (index < apis.size - 1) {
                    delay(RETRY_DELAY_MS)
                }
            }
        }

        return Result.failure(
            Exception(
                "❌ TikTok 解析失败\n\n已尝试 ${apis.size} 个 API 均不可用\n\n可能的原因：\n• 视频是私密内容\n• 视频已删除\n• 地区限制\n• API 服务限流\n\n建议：\n• 使用「导入本地视频」功能"
            )
        )
    }

