                        ?: videoData.optString("cover")
                        ?: videoData.optString("origin_cover")
                        ?: videoData.optString("dynamic_cover")

                    return@withContext Result.success(VideoDownloadInfo(
                        title = title,
                        downloadUrl = finalUrl,
                        cover = cover,
                        duration = videoData.optLong("duration", 0L),
                        author = author
                    ))
                }
            }

                return@withContext Result.success(VideoDownloadInfo(
                    title = title,
                    downloadUrl = finalUrl,
                    cover = json.optString("cover") ?: json.optString("thumb") ?: json.optString("origin_cover"),
                    duration = json.optLong("duration", 0L),
                    author = json.optString("author") ?: json.optString("nickname")
                ))
            }

            // 格式3: 嵌套在 data.video 或 data.video.play_addr 中
            val nestedVideo = json.optJSONObject("data")?.optJSONObject("video")
            if (nestedVideo != null) {
                val videoUrl = nestedVideo.optString("play_addr")
                    ?: nestedVideo.optString("play_addr_https")
                    ?: nestedVideo.optString("download_addr")
                    ?: nestedVideo.optString("download_addr_https")

                if (videoUrl.isNotEmpty() && (videoUrl.startsWith("http") || videoUrl.startsWith("//"))) {
                    val finalUrl = if (videoUrl.startsWith("//")) "https:$videoUrl" else videoUrl
                    return@withContext Result.success(VideoDownloadInfo(
                        title = json.optJSONObject("data")?.optString("desc") ?: "抖音视频",
                        downloadUrl = finalUrl,
                        cover = nestedVideo.optString("cover") ?: nestedVideo.optString("origin_cover"),
                        duration = nestedVideo.optJSONObject("video")?.optLong("duration", 0L) ?: 0L,
                        author = json.optJSONObject("data")?.optJSONObject("author")?.optString("nickname")
                    ))
                }
            }

            // 无法获取视频链接
            return@withContext Result.failure(Exception("无法从API响应中提取视频链接"))

        } catch (e: Exception) {
            Log.e(TAG, "[${api.name}] Request failed", e)
            Result.failure(e)
        }
    }

    /**
     * 获取 TikTok 视频信息 - 改进版
     * TikTok 和抖音解析逻辑相似，尝试多个 API
     */
    private suspend fun fetchTiktokInfo(url: String): Result<VideoDownloadInfo> {
        Log.d(TAG, "Fetching TikTok info for: $url")

        // TikTok 可以使用与抖音类似的 API
        val apis = listOf(
            // API 1: tikwm (专门用于 TikTok)
            TiktokApiConfig("https://www.tikwm.com/api/?url=$url", "tikwm"),
            // API 2: 通用 API
            TiktokApiConfig("https://api.pearktrue.com/api/v1/parse/tiktok?url=$url", "pearktrue"),
            // API 3: other API
            TiktokApiConfig("https://api.xboba.com/tiktok/video/download?url=$url", "xboba")
        )

        for ((index, api) in apis.withIndex()) {
            try {
                Log.d(TAG, "[${index + 1}/${apis.size}] Trying TikTok API: ${api.name}")

                val result = fetchTiktokInfoWithApi(api)
                if (result.isSuccess) {
                    Log.d(TAG, "Successfully fetched info using: ${api.name}")
                    return result
                }

                Log.w(TAG, "API ${api.name} failed: ${result.exceptionOrNull()?.message}")

                if (index < apis.size - 1) {
                    delay(RETRY_DELAY_MS)
                }
            } catch (e: Exception) {
                Log.e(TAG, "API ${api.name} threw exception", e)
                if (index < apis.size - 1) {
                    delay(RETRY_DELAY_MS)
                }
            }
        }

        return Result.failure(
            Exception(
                "❌ TikTok 解析失败\n\n已尝试 ${apis.size} 个 API 均不可用\n\n可能的原因：\n• 视频是私密内容\n• 视频已删除\n• 地区限制\n• API 服务限流\n\n建议：\n• 使用「导入本地视频」功能"
            )
        )
    }

    /**
     * 使用指定 API 获取 TikTok 视频信息
     */
    private suspend fun fetchTiktokInfoWithApi(api: TiktokApiConfig): Result<VideoDownloadInfo> = withContext(Dispatchers.IO) {
        try {
            val request = Request.Builder()
                .url(api.endpoint)
                .header("User-Agent", getUserAgent())
                .header("Referer", "https://www.tiktok.com/")
                .build()

            val response = client.newCall(request).execute()
            val responseBody = response.body?.string() ?: return@withContext Result.failure(IOException("空响应"))

            Log.d(TAG, "[${api.name}] Response: ${responseBody.take(300)}")

            if (responseBody.trim().startsWith("<!DOCTYPE") || responseBody.trim().startsWith("<html")) {
                return@withContext Result.failure(Exception("API返回HTML，可能已失效"))
            }

            val json = JSONObject(responseBody)

            // tikwm API 格式: {code: 0, data: {title: "...", play: "...", ...}}
            if (api.name == "tikwm") {
                if (json.optInt("code") == 0 && json.has("data")) {
                    val data = json.getJSONObject("data")
                    val videoUrl = data.optString("play")
                        ?: data.optString("hdplay")
                        ?: data.optString("wmplay")

                    if (videoUrl.startsWith("http")) {
                        return@withContext Result.success(VideoDownloadInfo(
                            title = data.optString("title") ?: "TikTok 视频",
                            downloadUrl = videoUrl,
                            cover = data.optString("cover") ?: data.optString("origin_cover"),
                            duration = data.optLong("duration", 0L),
                            author = data.optJSONObject("author")?.optString("nickname")
                        ))
                    }
                }
            }

            // 其他 API 通用格式
            val code = json.optInt("code")
            if (code != 200 && code != 1 && code != 0) {
                val msg = json.optString("msg") ?: json.optString("message") ?: "未知错误"
                return@withContext Result.failure(Exception("API返回错误($code): $msg"))
            }

            if (json.has("data")) {
                val data = json.getJSONObject("data")
                val videoData = data.optJSONArray("video")?.optJSONObject(0) ?: data

                val videoUrl = videoData.optString("play_addr")
                    ?: videoData.optString("url")
                    ?: data.optString("video_url")

                if (videoUrl.isNotEmpty() && videoUrl.startsWith("http")) {
                    return@withContext Result.success(VideoDownloadInfo(
                        title = data.optString("desc") ?: data.optString("title") ?: "TikTok 视频",
                        downloadUrl = videoUrl,
                        cover = data.optString("cover") ?: data.optString("thumb"),
                        duration = videoData.optLong("duration", 0L),
                        author = data.optJSONObject("author")?.optString("nickname")
                    ))
                }
            }

            // 直接格式
            val directUrl = json.optString("url") ?: json.optString("video_url")
            if (directUrl.startsWith("http")) {
                return@withContext Result.success(VideoDownloadInfo(
                    title = json.optString("title") ?: "TikTok 视频",
                    downloadUrl = directUrl,
                    cover = json.optString("cover"),
                    duration = json.optLong("duration", 0L)
                ))
            }

            return@withContext Result.failure(Exception("无法从API响应中提取视频链接"))

        } catch (e: Exception) {
            Log.e(TAG, "[${api.name}] Request failed", e)
            Result.failure(e)
        }
    }

    /**
     * 获取标准 User-Agent
     * 参考 Electron 版本使用真实的浏览器 UA
     */
    private fun getUserAgent(): String {
        return "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 " +
               "(KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"
    }

    /**
     * 获取小红书视频信息
     * 支持格式：
     * - https://www.xiaohongshu.com/explore/{noteId}
     * - https://www.xiaohongshu.com/discovery/item/{noteId}
     * - https://xhslink.com/{shortId}
     *
     * 参考 GitHub 项目：
     * - NanmiCoder/MediaCrawler (小红书爬虫)
     * - reajason/xhs (小红书 API 封装)
     */
    private suspend fun fetchXiaohongshuInfo(url: String): Result<VideoDownloadInfo> {
        Log.d(TAG, "Fetching Xiaohongshu info for: $url")

        // 先尝试提取笔记 ID
        val noteId = extractXiaohongshuNoteId(url)
        Log.d(TAG, "Xiaohongshu note ID: $noteId")

        // 尝试多个 API（增加更多备用）
        // 注意：小红书反爬机制强，第三方 API 稳定性较差
        val apis = listOf(
            // API 1: pearktrue (相对稳定)
            XiaohongshuApiConfig("https://api.pearktrue.com/api/v1/parse/xiaohongshu?url=$url", "pearktrue"),
            // API 2: 805t (备用)
            XiaohongshuApiConfig("https://api.805t.cn/xiaohongshu/api?url=$url", "805t"),
            // API 3: y1les (备用)
            XiaohongshuApiConfig("https://api.y1les.cn/api/xiaohongshu?url=$url", "y1les"),
            // API 4: iktota (备用)
            XiaohongshuApiConfig("https://api.iktota.com/api/xiaohongshu?url=$url", "iktota"),
            // API 5: xboba (备用)
            XiaohongshuApiConfig("https://api.xboba.com/xiaohongshu/video/download?url=$url", "xboba"),
            // API 6: ciallo (备用)
            XiaohongshuApiConfig("https://api.ciallo.online/api/xiaohongshu?url=$url", "ciallo"),
            // API 7: yujn (备用)
            XiaohongshuApiConfig("https://api.yujn.cn/api/xiaohongshu/?url=$url", "yujn"),
            // API 8: 新增备用
            XiaohongshuApiConfig("https://api.hhlqilong.top/api/xiaohongshu?url=$url", "hhlqilong")
        )

        for ((index, api) in apis.withIndex()) {
            try {
                Log.d(TAG, "[${index + 1}/${apis.size}] Trying Xiaohongshu API: ${api.name}")

                // 健康检查
                if (!isApiHealthy(api.endpoint)) {
                    Log.w(TAG, "[${api.name}] API is marked as unhealthy, skipping")
                    continue
                }

                val result = fetchXiaohongshuInfoWithApi(api)
                if (result.isSuccess) {
                    Log.d(TAG, "Successfully fetched info using: ${api.name}")
                    updateApiHealth(api.endpoint, true, 0)
                    return result
                }
                Log.w(TAG, "API ${api.name} failed: ${result.exceptionOrNull()?.message}")
                updateApiHealth(api.endpoint, false, 0, result.exceptionOrNull()?.message)
            } catch (e: Exception) {
                Log.e(TAG, "API ${api.name} threw exception", e)
                updateApiHealth(api.endpoint, false, 0, e.message)
            }
        }

        return Result.failure(
            Exception("❌ 小红书解析失败\n\n已尝试 ${apis.size} 个 API 均不可用\n\n可能的原因：\n• 笔记是私密内容\n• 笔记已删除或不包含视频\n• API 服务限流\n• 链接格式错误\n\n建议：\n• 确认笔记链接有效且包含视频\n• 使用「导入本地视频」功能\n• 在电脑上使用 res-downloader 等工具")
        )
    }

    private suspend fun fetchXiaohongshuInfoWithApi(api: XiaohongshuApiConfig): Result<VideoDownloadInfo> = withContext(Dispatchers.IO) {
        try {
            val request = Request.Builder()
                .url(api.endpoint)
                .header("User-Agent", getUserAgent())
                .header("Referer", "https://www.xiaohongshu.com/")
                .build()

            val response = client.newCall(request).execute()
            val responseBody = response.body?.string() ?: return@withContext Result.failure(IOException("空响应"))

            Log.d(TAG, "[${api.name}] Response: ${responseBody.take(300)}")

            if (responseBody.trim().startsWith("<!DOCTYPE") || responseBody.trim().startsWith("<html")) {
                return@withContext Result.failure(Exception("API返回HTML，可能已失效"))
            }

            val json = JSONObject(responseBody)

            // 检查响应状态码
            val code = json.optInt("code")
            if (code != 200 && code != 1 && code != 0) {
                val msg = json.optString("msg") ?: json.optString("message") ?: "未知错误"
                return@withContext Result.failure(Exception("API返回错误($code): $msg"))
            }

            // 解析视频数据 - 支持多种返回格式
            if (json.has("data")) {
                val data = json.getJSONObject("data")

                // 尝试多种视频 URL 字段名
                val videoUrl = data.optString("url")
                    ?: data.optString("video_url")
                    ?: data.optString("play_addr")
                    ?: data.optString("download_addr")
                    ?: data.optString("videoUrl")
                    ?: data.optString("stream")
                    ?: data.optString("masterStream")

                // 尝试多种标题字段名
                val title = data.optString("title")
                    ?: data.optString("desc")
                    ?: data.optString("text")
                    ?: data.optString("note_title")
                    ?: data.optString("display_title")
                    ?: "小红书视频"

                if (videoUrl.isNotEmpty() && videoUrl.startsWith("http")) {
                    // 尝试多种封面字段名
                    val cover = data.optString("cover")
                        ?: data.optString("thumb")
                        ?: data.optString("thumbnail")
                        ?: data.optString("image_list")
                        ?: data.optString("coverImage")

                    // 尝试多种作者字段名
                    val author = data.optString("author")
                        ?: data.optString("nickname")
                        ?: data.optString("user_name")
                        ?: data.optString("userName")
                        ?: data.optJSONObject("user")?.optString("nickname")
                        ?: data.optJSONObject("user")?.optString("name")

                    return@withContext Result.success(VideoDownloadInfo(
                        title = title,
                        downloadUrl = videoUrl,
                        cover = cover,
                        duration = data.optLong("duration", 0L),
                        author = author
                    ))
                }

                // 尝试从嵌套的 video 字段中获取
                val videoData = data.optJSONObject("video")
                if (videoData != null) {
                    val nestedVideoUrl = videoData.optString("url")
                        ?: videoData.optString("stream")
                        ?: videoData.optString("play_addr")
                        ?: videoData.optString("download_addr")

                    if (nestedVideoUrl.isNotEmpty() && nestedVideoUrl.startsWith("http")) {
                        return@withContext Result.success(VideoDownloadInfo(
                            title = data.optString("title") ?: data.optString("desc") ?: "小红书视频",
                            downloadUrl = nestedVideoUrl,
                            cover = videoData.optString("cover") ?: data.optString("cover"),
                            duration = videoData.optLong("duration", 0L),
                            author = data.optString("author") ?: data.optString("nickname")
                        ))
                    }
                }
            }

            // 直接在根级别查找视频 URL
            val directUrl = json.optString("url")
                ?: json.optString("video_url")
                ?: json.optString("play_addr")

            if (directUrl.isNotEmpty() && directUrl.startsWith("http")) {
                return@withContext Result.success(VideoDownloadInfo(
                    title = json.optString("title") ?: json.optString("desc") ?: "小红书视频",
                    downloadUrl = directUrl,
                    cover = json.optString("cover") ?: json.optString("thumb"),
                    duration = json.optLong("duration", 0L),
                    author = json.optString("author") ?: json.optString("nickname")
                ))
            }

            Result.failure(Exception("无法从API响应中提取视频链接"))

        } catch (e: Exception) {
            Log.e(TAG, "[${api.name}] Request failed", e)
            Result.failure(e)
        }
    }

